package com.shecancode.user.model; import com.fasterxml.jackson.annotation.JsonIgnore; import jakarta.persistence.*; @Entity @Table(name="app_users") public class AppUser { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private String firstName; private String lastName; @Column(unique=true,nullable=false) private String email; @JsonIgnore private String password; private String role="CUSTOMER"; private boolean enabled=true; public AppUser(){} public AppUser(String f,String l,String e,String p,String r){firstName=f;lastName=l;email=e;password=p;role=r;} public Long getId(){return id;} public String getFirstName(){return firstName;} public void setFirstName(String v){firstName=v;} public String getLastName(){return lastName;} public void setLastName(String v){lastName=v;} public String getEmail(){return email;} public void setEmail(String v){email=v;} public String getPassword(){return password;} public void setPassword(String v){password=v;} public String getRole(){return role;} public void setRole(String v){role=v;} public boolean isEnabled(){return enabled;} public void setEnabled(boolean v){enabled=v;} }